require_once __DIR__.'/../../config/auth.php';require_once __DIR__.'/../../config/database.php';require_once __DIR__.'/../../config/helper.php';require_admin();$pdo=db();$id=(int)($_GET['id']??$_POST['id']??0);if(!$pdo||!$id){flash('error','Materi tidak ditemukan.');redirect('admin/materi/index.php');}$s=$pdo->prepare('SELECT * FROM materi WHERE id=?');$s->execute([$id]);$r=$s->fetch();if(!$r){flash('error','Materi tidak ditemukan.');redirect('admin/materi/index.php');}$cats=$pdo->query('SELECT id,nama FROM kategori_materi ORDER BY nama')->fetchAll();$errors=[];
